## 9. Real Example: Walking Through a Model

Given Prisma schema:
```prisma
model User {
  id    Int     @id @default(autoincrement())
  email String  @unique
  posts Post[]
}

model Post {
  id     Int    @id
  title  String
  userId Int
  user   User   @relation(fields: [userId], references: [id])
}
```

In DMMF:

```typescript
// dmmf.datamodel.models[0] (User model)
{
  name: 'User',
  dbName: null,
  fields: [
    {
      name: 'id',
      kind: 'scalar',
      type: 'Int',
      isRequired: true,
      isList: false,
      isId: true,
      hasDefaultValue: true,
      default: { name: 'autoincrement', args: [] },
      ...
    },
    {
      name: 'email',
      kind: 'scalar',
      type: 'String',
      isRequired: true,
      isList: false,
      isUnique: true,
      ...
    },
    {
      name: 'posts',
      kind: 'object',
      type: 'Post',        // References Post model
      isList: true,        // Array of Post
      isRequired: true,
      relationName: 'UserToPost',
      ...
    }
  ]
}

// dmmf.datamodel.models[1] (Post model)
{
  name: 'Post',
  fields: [
    { name: 'id', kind: 'scalar', type: 'Int', isId: true, ... },
    { name: 'title', kind: 'scalar', type: 'String', ... },
    {
      name: 'userId',
      kind: 'scalar',
      type: 'Int',
      relationFromFields: ['userId'],
      relationToFields: ['id'],
      relationName: 'UserToPost',
      ...
    },
    {
      name: 'user',
      kind: 'object',
      type: 'User',
      relationFromFields: ['userId'],
      relationToFields: ['id'],
      relationName: 'UserToPost',
      ...
    }
  ]
}
