import type { Field, Model } from '@prisma/dmmf'
import {
  array,
  interfaceDeclaration,
  moduleExport,
  namedType,
  property,
  stringify,
  unknownType,
  type TypeBuilder,
} from '@prisma/ts-builders'

import { mapScalarType } from './type-map'

function fieldToTypeBuilder(field: Field): TypeBuilder {
  switch (field.kind) {
    case 'scalar':
      return namedType(mapScalarType(field.type))
    case 'enum':
      return namedType(field.type)
    case 'object':
      return namedType(field.type)
    default:
      return unknownType
  }
}

function resolveFieldType(field: Field): TypeBuilder {
  const base = fieldToTypeBuilder(field)
  return field.isList ? array(base) : base
}

/**
 * Generates three interface declarations per model:
 *
 * - `<Model>` — the full row type with all scalar and enum fields
 * - `<Model>CreateInput` — writable fields for creation (excludes id,
 *    auto-generated, read-only, updated-at, and relation fields)
 * - `<Model>UpdateInput` — same writable fields but all optional
 */
export function generateModels(models: readonly Model[]): string {
  const parts: string[] = []

  for (const model of models) {
    const scalarFields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')

    // -- Full model interface --
    const modelIface = interfaceDeclaration(model.name)
    for (const field of scalarFields) {
      const prop = property(field.name, resolveFieldType(field))
      if (!field.isRequired) {
        prop.optional()
      }
      modelIface.add(prop)
    }
    parts.push(stringify(moduleExport(modelIface), { newLine: 'trailing' }))

    // -- CreateInput (exclude auto-managed fields) --
    const writableFields = scalarFields.filter(
      (f) => !f.isId && !f.isGenerated && !f.isReadOnly && !f.isUpdatedAt && !f.hasDefaultValue,
    )

    const createIface = interfaceDeclaration(`${model.name}CreateInput`)
    for (const field of writableFields) {
      const prop = property(field.name, resolveFieldType(field))
      if (!field.isRequired) {
        prop.optional()
      }
      createIface.add(prop)
    }
    parts.push(stringify(moduleExport(createIface), { newLine: 'trailing' }))

    // -- UpdateInput (all writable fields optional) --
    const updateIface = interfaceDeclaration(`${model.name}UpdateInput`)
    for (const field of writableFields) {
      const prop = property(field.name, resolveFieldType(field))
      prop.optional()
      updateIface.add(prop)
    }
    parts.push(stringify(moduleExport(updateIface), { newLine: 'trailing' }))
  }

  return parts.join('\n')
}

