import type * as DMMF from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { generate } from '../generate'
import { generateClient } from '../generate-client'
import { generateEnums } from '../generate-enums'
import { generateModels } from '../generate-models'
import { mapScalarType } from '../type-map'

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    isGenerated: false,
    isUpdatedAt: false,
    hasDefaultValue: false,
    ...overrides,
  }
}

function makeModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  }
}

function minimalDmmf(
  models: DMMF.Model[],
  enums: DMMF.DatamodelEnum[] = [],
): DMMF.Document {
  return {
    datamodel: { models, enums, types: [] },
    schema: {
      inputObjectTypes: {},
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
  }
}

// ---------------------------------------------------------------------------
// type-map
// ---------------------------------------------------------------------------

describe('mapScalarType', () => {
  test('maps common Prisma scalars to TS types', () => {
    expect(mapScalarType('String')).toBe('string')
    expect(mapScalarType('Int')).toBe('number')
    expect(mapScalarType('Float')).toBe('number')
    expect(mapScalarType('Boolean')).toBe('boolean')
    expect(mapScalarType('DateTime')).toBe('string')
    expect(mapScalarType('BigInt')).toBe('string')
    expect(mapScalarType('Decimal')).toBe('string')
    expect(mapScalarType('Json')).toBe('unknown')
    expect(mapScalarType('Bytes')).toBe('string')
  })

  test('returns unknown for unrecognised types', () => {
    expect(mapScalarType('Foo')).toBe('unknown')
  })
})

// ---------------------------------------------------------------------------
// generate-enums
// ---------------------------------------------------------------------------

describe('generateEnums', () => {
  test('produces string-union types for enums', () => {
    const enums: DMMF.DatamodelEnum[] = [
      { name: 'Role', values: [{ name: 'ADMIN', dbName: null }, { name: 'USER', dbName: null }] },
    ]
    const code = generateEnums(enums)
    expect(code).toContain('export type Role =')
    expect(code).toContain('"ADMIN"')
    expect(code).toContain('"USER"')
  })

  test('returns empty string when no enums', () => {
    expect(generateEnums([])).toBe('')
  })
})

// ---------------------------------------------------------------------------
// generate-models
// ---------------------------------------------------------------------------

describe('generateModels', () => {
  const userModel = makeModel('User', [
    makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
    makeField({ name: 'email', type: 'String', isUnique: true }),
    makeField({ name: 'name', type: 'String', isRequired: false }),
    makeField({ name: 'age', type: 'Int' }),
    makeField({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true }),
    makeField({ name: 'updatedAt', type: 'DateTime', isUpdatedAt: true }),
    makeField({ name: 'posts', type: 'Post', kind: 'object', isList: true }),
  ])

  test('generates the full model interface with scalar/enum fields only', () => {
    const code = generateModels([userModel])
    expect(code).toContain('export interface User {')
    expect(code).toContain('id: string')
    expect(code).toContain('email: string')
    expect(code).toContain('name?: string')
    expect(code).toContain('age: number')
    // relation fields are excluded
    expect(code).not.toContain('posts')
  })

  test('generates CreateInput excluding auto-managed fields', () => {
    const code = generateModels([userModel])
    expect(code).toContain('export interface UserCreateInput {')
    // id (isId+hasDefault), createdAt (hasDefault), updatedAt (isUpdatedAt) are excluded
    expect(code).toMatch(/UserCreateInput\s*\{[^}]*email: string/)
    expect(code).toMatch(/UserCreateInput\s*\{[^}]*age: number/)
    // id, createdAt, updatedAt should NOT be in CreateInput
    expect(code).not.toMatch(/UserCreateInput\s*\{[^}]*\bid\b/)
  })

  test('generates UpdateInput with all fields optional', () => {
    const code = generateModels([userModel])
    expect(code).toContain('export interface UserUpdateInput {')
    expect(code).toMatch(/UserUpdateInput\s*\{[^}]*email\?: string/)
    expect(code).toMatch(/UserUpdateInput\s*\{[^}]*age\?: number/)
  })

  test('handles list fields as arrays', () => {
    const model = makeModel('Tag', [
      makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
      makeField({ name: 'names', type: 'String', isList: true }),
    ])
    const code = generateModels([model])
    expect(code).toContain('names: string[]')
  })

  test('handles enum fields', () => {
    const model = makeModel('Account', [
      makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
      makeField({ name: 'role', type: 'Role', kind: 'enum' }),
    ])
    const code = generateModels([model])
    expect(code).toContain('role: Role')
  })
})

// ---------------------------------------------------------------------------
// generate-client
// ---------------------------------------------------------------------------

describe('generateClient', () => {
  const models = [
    makeModel('User', [
      makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
      makeField({ name: 'email', type: 'String' }),
    ]),
    makeModel('Post', [
      makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
      makeField({ name: 'title', type: 'String' }),
    ]),
  ]

  test('generates delegate classes with CRUD methods', () => {
    const code = generateClient(models)
    expect(code).toContain('class UserDelegate')
    expect(code).toContain('class PostDelegate')
    expect(code).toContain('async findMany(): Promise<User[]>')
    expect(code).toContain('async findUnique(id: string): Promise<User | null>')
    expect(code).toContain('async create(data: UserCreateInput): Promise<User>')
    expect(code).toContain('async update(id: string, data: UserUpdateInput): Promise<User>')
    expect(code).toContain('async delete(id: string): Promise<User>')
  })

  test('generates the RestApiClient class with delegate properties', () => {
    const code = generateClient(models)
    expect(code).toContain('export class RestApiClient')
    expect(code).toContain('readonly user: UserDelegate')
    expect(code).toContain('readonly post: PostDelegate')
    expect(code).toContain('constructor(baseUrl: string)')
  })

  test('uses pluralised lowercase paths', () => {
    const code = generateClient(models)
    expect(code).toContain('/users')
    expect(code).toContain('/posts')
  })
})

// ---------------------------------------------------------------------------
// generate (orchestrator)
// ---------------------------------------------------------------------------

describe('generate', () => {
  test('produces a complete file with header, enums, models, and client', () => {
    const dmmf = minimalDmmf(
      [
        makeModel('User', [
          makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
          makeField({ name: 'email', type: 'String' }),
          makeField({ name: 'role', type: 'Role', kind: 'enum' }),
        ]),
      ],
      [{ name: 'Role', values: [{ name: 'ADMIN', dbName: null }, { name: 'USER', dbName: null }] }],
    )

    const code = generate(dmmf)

    // Header
    expect(code).toContain('Auto-generated by @prisma/generator-rest-api')

    // Enum
    expect(code).toContain('export type Role =')

    // Model interfaces
    expect(code).toContain('export interface User {')
    expect(code).toContain('export interface UserCreateInput {')
    expect(code).toContain('export interface UserUpdateInput {')

    // Client class
    expect(code).toContain('export class RestApiClient')
    expect(code).toContain('readonly user: UserDelegate')
  })

  test('works with an empty schema', () => {
    const dmmf = minimalDmmf([])
    const code = generate(dmmf)
    expect(code).toContain('Auto-generated by @prisma/generator-rest-api')
    expect(code).not.toContain('export interface')
  })

  test('handles multiple models', () => {
    const dmmf = minimalDmmf([
      makeModel('User', [
        makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
        makeField({ name: 'email', type: 'String' }),
      ]),
      makeModel('Post', [
        makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
        makeField({ name: 'title', type: 'String' }),
        makeField({ name: 'published', type: 'Boolean' }),
      ]),
    ])

    const code = generate(dmmf)

    expect(code).toContain('export interface User {')
    expect(code).toContain('export interface Post {')
    expect(code).toContain('export class RestApiClient')
    expect(code).toContain('readonly user: UserDelegate')
    expect(code).toContain('readonly post: PostDelegate')
  })
})

