import fs from 'node:fs'
import path from 'node:path'

import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generate } from './generate'

/** Prisma generator that produces a typed REST API client from a Prisma schema. */
export class RestApiGenerator implements Generator {
  readonly name = 'prisma-rest-api'

  async getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return {
      prettyName: 'Prisma REST API Client',
      defaultOutput: './generated/rest-api-client',
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = options.generator.output?.value
    if (!outputDir) {
      throw new Error('@prisma/generator-rest-api: no output directory specified')
    }

    const code = generate(options.dmmf)

    fs.mkdirSync(outputDir, { recursive: true })
    fs.writeFileSync(path.join(outputDir, 'index.ts'), code, 'utf-8')
  }
}

import type * as DMMF from '@prisma/dmmf'

import { generateClient } from './generate-client'
import { generateEnums } from './generate-enums'
import { generateModels } from './generate-models'

/** Header prepended to every generated file. */
const FILE_HEADER = [
  '// ---------------------------------------------------------------',
  '// Auto-generated by @prisma/generator-rest-api — DO NOT EDIT',
  '// ---------------------------------------------------------------',
  '',
].join('\n')

/**
 * Orchestrates the full code generation pipeline.
 *
 * Takes a DMMF document and returns the complete TypeScript source for a
 * typed REST API client covering every model in the schema.
 */
export function generate(dmmf: DMMF.Document): string {
  const { models, enums } = dmmf.datamodel

  const sections: string[] = [FILE_HEADER]

  const enumCode = generateEnums(enums)
  if (enumCode) {
    sections.push(enumCode)
  }

  sections.push(generateModels(models))
  sections.push(generateClient(models))
  sections.push('') // trailing newline

  return sections.join('\n')
}

import type { DatamodelEnum } from '@prisma/dmmf'
import { moduleExport, stringify, typeDeclaration, unionType, stringLiteral } from '@prisma/ts-builders'

/** Generates TypeScript string-union type declarations for each Prisma enum. */
export function generateEnums(enums: readonly DatamodelEnum[]): string {
  if (enums.length === 0) return ''

  const parts: string[] = []

  for (const enumDef of enums) {
    const variants = enumDef.values.map((v) => stringLiteral(v.name))
    const decl = typeDeclaration(enumDef.name, unionType(variants))
    parts.push(stringify(moduleExport(decl), { newLine: 'trailing' }))
  }

  return parts.join('\n')
}

import type { Field, Model } from '@prisma/dmmf'
import {
  array,
  interfaceDeclaration,
  moduleExport,
  namedType,
  property,
  stringify,
  unknownType,
  type TypeBuilder,
} from '@prisma/ts-builders'

import { mapScalarType } from './type-map'

function fieldToTypeBuilder(field: Field): TypeBuilder {
  switch (field.kind) {
    case 'scalar':
      return namedType(mapScalarType(field.type))
    case 'enum':
      return namedType(field.type)
    case 'object':
      return namedType(field.type)
    default:
      return unknownType
  }
}

function resolveFieldType(field: Field): TypeBuilder {
  const base = fieldToTypeBuilder(field)
  return field.isList ? array(base) : base
}

/**
 * Generates three interface declarations per model:
 *
 * - `<Model>` — the full row type with all scalar and enum fields
 * - `<Model>CreateInput` — writable fields for creation (excludes id,
 *    auto-generated, read-only, updated-at, and relation fields)
 * - `<Model>UpdateInput` — same writable fields but all optional
 */
export function generateModels(models: readonly Model[]): string {
  const parts: string[] = []

  for (const model of models) {
    const scalarFields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')

    // -- Full model interface --
    const modelIface = interfaceDeclaration(model.name)
    for (const field of scalarFields) {
      const prop = property(field.name, resolveFieldType(field))
      if (!field.isRequired) {
        prop.optional()
      }
      modelIface.add(prop)
    }
    parts.push(stringify(moduleExport(modelIface), { newLine: 'trailing' }))

    // -- CreateInput (exclude auto-managed fields) --
    const writableFields = scalarFields.filter(
      (f) => !f.isId && !f.isGenerated && !f.isReadOnly && !f.isUpdatedAt && !f.hasDefaultValue,
    )

    const createIface = interfaceDeclaration(`${model.name}CreateInput`)
    for (const field of writableFields) {
      const prop = property(field.name, resolveFieldType(field))
      if (!field.isRequired) {
        prop.optional()
      }
      createIface.add(prop)
    }
    parts.push(stringify(moduleExport(createIface), { newLine: 'trailing' }))

    // -- UpdateInput (all writable fields optional) --
    const updateIface = interfaceDeclaration(`${model.name}UpdateInput`)
    for (const field of writableFields) {
      const prop = property(field.name, resolveFieldType(field))
      prop.optional()
      updateIface.add(prop)
    }
    parts.push(stringify(moduleExport(updateIface), { newLine: 'trailing' }))
  }

  return parts.join('\n')
}

