import type { Model } from '@prisma/dmmf'

/**
 * Emits a model delegate class that exposes typed CRUD methods backed by
 * `fetch()`. Each delegate is parameterised with the model's row type and
 * its create/update input types.
 */
function generateDelegate(model: Model): string {
  const name = model.name
  const lowerName = name[0].toLowerCase() + name.slice(1)
  const pluralPath = `${lowerName}s`

  return `class ${name}Delegate {
  #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl
  }

  async findMany(): Promise<${name}[]> {
    const response = await fetch(\`\${this.#baseUrl}/${pluralPath}\`)
    if (!response.ok) throw new Error(\`GET /${pluralPath} failed: \${response.statusText}\`)
    return (await response.json()) as ${name}[]
  }

  async findUnique(id: string): Promise<${name} | null> {
    const response = await fetch(\`\${this.#baseUrl}/${pluralPath}/\${id}\`)
    if (response.status === 404) return null
    if (!response.ok) throw new Error(\`GET /${pluralPath}/\${id} failed: \${response.statusText}\`)
    return (await response.json()) as ${name}
  }

  async create(data: ${name}CreateInput): Promise<${name}> {
    const response = await fetch(\`\${this.#baseUrl}/${pluralPath}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!response.ok) throw new Error(\`POST /${pluralPath} failed: \${response.statusText}\`)
    return (await response.json()) as ${name}
  }

  async update(id: string, data: ${name}UpdateInput): Promise<${name}> {
    const response = await fetch(\`\${this.#baseUrl}/${pluralPath}/\${id}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!response.ok) throw new Error(\`PATCH /${pluralPath}/\${id} failed: \${response.statusText}\`)
    return (await response.json()) as ${name}
  }

  async delete(id: string): Promise<${name}> {
    const response = await fetch(\`\${this.#baseUrl}/${pluralPath}/\${id}\`, {
      method: 'DELETE',
    })
    if (!response.ok) throw new Error(\`DELETE /${pluralPath}/\${id} failed: \${response.statusText}\`)
    return (await response.json()) as ${name}
  }
}`
}

/**
 * Generates the `RestApiClient` class with a property for each model
 * delegate.
 */
export function generateClient(models: readonly Model[]): string {
  const delegates = models.map(generateDelegate)

  const delegateProperties = models
    .map((m) => {
      const lowerName = m.name[0].toLowerCase() + m.name.slice(1)
      return `  readonly ${lowerName}: ${m.name}Delegate`
    })
    .join('\n')

  const delegateAssignments = models
    .map((m) => {
      const lowerName = m.name[0].toLowerCase() + m.name.slice(1)
      return `    this.${lowerName} = new ${m.name}Delegate(baseUrl)`
    })
    .join('\n')

  const clientClass = `export class RestApiClient {
${delegateProperties}

  constructor(baseUrl: string) {
${delegateAssignments}
  }
}`

  return [...delegates, '', clientClass].join('\n\n')
}

